/**
 * @summary Register content hash on blockchain
 */
export const getRegisterOnBlockchainUrl = () => {
  return `/api/web3/register`;
};

export const registerOnBlockchain = async (
  blockchainRegisterRequest: BlockchainRegisterRequest,
  options?: RequestInit,
): Promise<BlockchainRecord> => {
  return customFetch<BlockchainRecord>(getRegisterOnBlockchainUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(blockchainRegisterRequest),
  });
};

export const getRegisterOnBlockchainMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof registerOnBlockchain>>,
    TError,
    { data: BodyType<BlockchainRegisterRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof registerOnBlockchain>>,
  TError,
  { data: BodyType<BlockchainRegisterRequest> },
  TContext
> => {
  const mutationKey = ["registerOnBlockchain"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof registerOnBlockchain>>,
    { data: BodyType<BlockchainRegisterRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return registerOnBlockchain(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type RegisterOnBlockchainMutationResult = NonNullable<
  Awaited<ReturnType<typeof registerOnBlockchain>>
>;
export type RegisterOnBlockchainMutationBody =
  BodyType<BlockchainRegisterRequest>;
export type RegisterOnBlockchainMutationError = ErrorType<unknown>;

/**
 * @summary Register content hash on blockchain
 */
export const useRegisterOnBlockchain = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof registerOnBlockchain>>,
    TError,
    { data: BodyType<BlockchainRegisterRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof registerOnBlockchain>>,
  TError,
  { data: BodyType<BlockchainRegisterRequest> },
  TContext
> => {
  return useMutation(getRegisterOnBlockchainMutationOptions(options));
};

